## 3. QueryDSL Projection 최적화

파일 위치: `domain/src/main/kotlin/com/maum/backend/repository/follow/FollowQueryRepository.kt`

### 3-1. DTO Projection 클래스

```kotlin
// domain/src/main/kotlin/com/maum/backend/dto/follow/FollowUserDto.kt

data class FollowUserDto(
    // Follow 정보
    val followId: String,
    val createdAt: LocalDateTime,
    // User 정보 (JOIN으로 한 번에)
    val userId: String,
    val nickname: String,
    val profileImageUrl: String?,
    val mannerScore: Double,
) {
    // 커서 인코딩: Base64(createdAt|followId)
    val cursor: String
        get() = Base64.getEncoder().encodeToString(
            "${createdAt}|${followId}".toByteArray()
        )
}

data class FollowPageResult(
    val items: List<FollowUserDto>,
    val hasNextPage: Boolean,
    val endCursor: String?,
)
```

### 3-2. QueryDSL Repository (N+1 완전 제거)

**Before (N+1 문제 발생):**

```kotlin
// 문제: follows 조회 후 각 userId로 User 개별 조회 → N+1
fun getFollowingList(userId: String, limit: Int): List<FollowUserDto> {
    val follows = followRepository.findByFollowerId(userId) // 쿼리 1번
    return follows.map { follow ->
        val user = userRepository.findById(follow.followingId).get() // N번 추가 쿼리!
        FollowUserDto(
            followId = follow.id,
            userId = user.id,
            nickname = user.nickname,
            // ...
        )
    }
}
```

**After (단일 쿼리로 해결):**

```kotlin
// domain/src/main/kotlin/com/maum/backend/repository/follow/FollowQueryRepository.kt

@Repository
class FollowQueryRepository(
    private val queryFactory: JPAQueryFactory,
) {
    private val follow = QFollowEntity.followEntity
    private val user = QUserEntity.userEntity

    /**
     * 팔로잉 목록 커서 기반 조회 (내가 팔로우하는 사람들)
     * - Follow + User JOIN으로 N+1 완전 제거
     * - 커버링 인덱스 활용을 위해 Projection에서 필요 컬럼만 선택
     */
    fun getFollowingPage(
        followerId: String,
        cursor: FollowCursor?,
        pageSize: Int,
    ): FollowPageResult {
        val fetchSize = pageSize + 1 // hasNextPage 판별용 1개 초과 조회

        val results = queryFactory
            .select(
                Projections.constructor(
                    FollowUserDto::class.java,
                    follow.id,
                    follow.createdAt,
                    user.id,
                    user.nickname,
                    user.profileImageUrl,
                    user.mannerScore,
                )
            )
            .from(follow)
            // JOIN: follows + users 한 번에 → N+1 제거
            .innerJoin(user).on(
                follow.followingId.eq(user.id),
                user.deletedAt.isNull, // 탈퇴 유저 제외
            )
            .where(
                follow.followerId.eq(followerId),
                follow.status.eq(FollowStatus.ACTIVE),
                // 커서 조건: (created_at, id) < (cursor_time, cursor_id)
                cursorCondition(cursor),
            )
            .orderBy(follow.createdAt.desc(), follow.id.desc())
            .limit(fetchSize.toLong())
            .fetch()

        val hasNextPage = results.size > pageSize
        val items = if (hasNextPage) results.dropLast(1) else results

        return FollowPageResult(
            items = items,
            hasNextPage = hasNextPage,
            endCursor = items.lastOrNull()?.cursor,
        )
    }

    /**
     * 팔로워 목록 커서 기반 조회 (나를 팔로우하는 사람들)
     */
    fun getFollowerPage(
        followingId: String,
        cursor: FollowCursor?,
        pageSize: Int,
    ): FollowPageResult {
        val fetchSize = pageSize + 1

        val results = queryFactory
            .select(
                Projections.constructor(
                    FollowUserDto::class.java,
                    follow.id,
                    follow.createdAt,
                    user.id,
                    user.nickname,
                    user.profileImageUrl,
                    user.mannerScore,
                )
            )
            .from(follow)
            .innerJoin(user).on(
                follow.followerId.eq(user.id), // 팔로워 방향
                user.deletedAt.isNull,
            )
            .where(
                follow.followingId.eq(followingId),
                follow.status.eq(FollowStatus.ACTIVE),
                cursorCondition(cursor),
            )
            .orderBy(follow.createdAt.desc(), follow.id.desc())
            .limit(fetchSize.toLong())
            .fetch()

        val hasNextPage = results.size > pageSize
        val items = if (hasNextPage) results.dropLast(1) else results

        return FollowPageResult(
            items = items,
            hasNextPage = hasNextPage,
            endCursor = items.lastOrNull()?.cursor,
        )
    }

    /**
     * 커서 조건: (created_at, id) 복합 커서
     * 인덱스 레인지 스캔을 유지하면서 정확한 페이지 구분
     */
    private fun cursorCondition(cursor: FollowCursor?): BooleanExpression? {
        if (cursor == null) return null
        // (created_at < cursor.time) OR (created_at = cursor.time AND id < cursor.id)
        return follow.createdAt.lt(cursor.createdAt)
            .or(
                follow.createdAt.eq(cursor.createdAt)
                    .and(follow.id.lt(cursor.id))
            )
    }
}

data class FollowCursor(val createdAt: LocalDateTime, val id: String) {
    companion object {
        fun decode(encoded: String): FollowCursor {
            val decoded = String(Base64.getDecoder().decode(encoded))
            val (timeStr, id) = decoded.split("|")
            return FollowCursor(
                createdAt = LocalDateTime.parse(timeStr),
                id = id,
            )
        }
    }
}
```

