## 5. GraphQL Relay 커서 기반 페이지네이션

### 5-1. GraphQL 스키마

파일 위치: `graphql/src/main/resources/graphql/follow.graphqls`

```graphql
# GraphQL Relay Connection Spec 준수

type FollowUser {
    userId: ID!
    nickname: String!
    profileImageUrl: String
    mannerScore: Float!
    followedAt: String!
}

type FollowEdge {
    node: FollowUser!
    cursor: String!         # Base64 인코딩된 커서
}

type PageInfo {
    hasNextPage: Boolean!
    hasPreviousPage: Boolean!
    startCursor: String
    endCursor: String
}

type FollowConnection {
    edges: [FollowEdge!]!
    pageInfo: PageInfo!
    totalCount: Int!        # 캐시된 값 사용
}

extend type Query {
    # 팔로잉 목록 (내가 팔로우하는 사람들)
    followings(
        first: Int = 20
        after: String       # endCursor 값
    ): FollowConnection!

    # 팔로워 목록 (나를 팔로우하는 사람들)
    followers(
        first: Int = 20
        after: String
    ): FollowConnection!

    # 특정 유저 팔로우 여부
    isFollowing(targetUserId: ID!): Boolean!
}

extend type Mutation {
    follow(targetUserId: ID!): Boolean!
    unfollow(targetUserId: ID!): Boolean!
}
```

### 5-2. GraphQL Controller

파일 위치: `graphql/src/main/kotlin/com/maum/backend/controller/follow/FollowController.kt`

```kotlin
@Controller
class FollowController(
    private val followQueryService: FollowQueryService,
    private val followCacheService: FollowCacheService,
) {
    /**
     * 팔로잉 목록 (Relay Connection)
     * - cursor 없으면 첫 페이지 → Redis 캐시 우선 조회
     * - cursor 있으면 DB 직접 조회
     */
    @QueryMapping
    @PreAuthorize("hasAuthority('User')")
    suspend fun followings(
        @UserId userId: String,
        @Argument first: Int?,
        @Argument after: String?,
    ): FollowConnection {
        val pageSize = (first ?: 20).coerceIn(1, 100)
        val cursor = after?.let { FollowCursor.decode(it) }

        val result = if (cursor == null) {
            // 첫 페이지: 캐시 우선
            followCacheService.getFollowingFirstPage(userId, pageSize)
        } else {
            // 이후 페이지: DB 직접
            withContext(Dispatchers.IO) {
                followQueryService.getFollowingPage(userId, cursor, pageSize)
            }
        }

        val totalCount = followCacheService.getFollowingCount(userId)

        return result.toConnection(totalCount)
    }

    @QueryMapping
    @PreAuthorize("hasAuthority('User')")
    suspend fun followers(
        @UserId userId: String,
        @Argument first: Int?,
        @Argument after: String?,
    ): FollowConnection {
        val pageSize = (first ?: 20).coerceIn(1, 100)
        val cursor = after?.let { FollowCursor.decode(it) }

        val result = withContext(Dispatchers.IO) {
            followQueryService.getFollowerPage(userId, cursor, pageSize)
        }
        val totalCount = followCacheService.getFollowerCount(userId)

        return result.toConnection(totalCount)
    }

    @QueryMapping
    @PreAuthorize("hasAuthority('User')")
    suspend fun isFollowing(
        @UserId userId: String,
        @Argument targetUserId: String,
    ): Boolean = followCacheService.isFollowing(userId, targetUserId)
}

// DTO 변환 확장 함수
fun FollowPageResult.toConnection(totalCount: Long): FollowConnection =
    FollowConnection(
        edges = items.map { dto ->
            FollowEdge(
                node = FollowUser(
                    userId = dto.userId,
                    nickname = dto.nickname,
                    profileImageUrl = dto.profileImageUrl,
                    mannerScore = dto.mannerScore,
                    followedAt = dto.createdAt.toString(),
                ),
                cursor = dto.cursor,
            )
        },
        pageInfo = PageInfo(
            hasNextPage = hasNextPage,
            hasPreviousPage = false, // 단방향 커서
            startCursor = items.firstOrNull()?.cursor,
            endCursor = endCursor,
        ),
        totalCount = totalCount,
    )
```

