### 4-2. 캐시 서비스 구현

```kotlin
// domain/src/main/kotlin/com/maum/backend/service/follow/FollowCacheService.kt

@Service
class FollowCacheService(
    private val redisTemplate: RedisTemplate<String, String>,
    private val followQueryRepository: FollowQueryRepository,
    private val followRepository: FollowRepository,
    private val objectMapper: ObjectMapper,
) {
    companion object {
        val FOLLOWER_COUNT_TTL: Duration = Duration.ofMinutes(5)
        val FOLLOWING_COUNT_TTL: Duration = Duration.ofMinutes(5)
        val IS_FOLLOWING_TTL: Duration = Duration.ofMinutes(10)
        val FIRST_PAGE_TTL: Duration = Duration.ofMinutes(1)
    }

    private val ops = redisTemplate.opsForValue()

    /**
     * 팔로워 수 조회 (Cache-Aside 패턴)
     * Before: COUNT(*) 매번 실행 → 50ms+
     * After: Redis 히트 시 <1ms
     */
    suspend fun getFollowerCount(userId: String): Long {
        val key = FollowCacheKeys.followerCount(userId)
        val cached = ops.get(key)
        if (cached != null) return cached.toLong()

        // Cache Miss: DB 조회 후 캐싱
        val count = withContext(Dispatchers.IO) {
            followRepository.countByFollowingIdAndStatus(userId, FollowStatus.ACTIVE)
        }
        ops.set(key, count.toString(), FOLLOWER_COUNT_TTL)
        return count
    }

    /**
     * 팔로잉 수 조회
     */
    suspend fun getFollowingCount(userId: String): Long {
        val key = FollowCacheKeys.followingCount(userId)
        val cached = ops.get(key)
        if (cached != null) return cached.toLong()

        val count = withContext(Dispatchers.IO) {
            followRepository.countByFollowerIdAndStatus(userId, FollowStatus.ACTIVE)
        }
        ops.set(key, count.toString(), FOLLOWING_COUNT_TTL)
        return count
    }

    /**
     * 팔로우 여부 확인 (프로필 화면에서 가장 자주 호출)
     * Before: SELECT 1 FROM follows WHERE follower_id=? AND following_id=?
     * After: Redis String 값 1회 조회
     */
    suspend fun isFollowing(followerId: String, followingId: String): Boolean {
        val key = FollowCacheKeys.isFollowing(followerId, followingId)
        val cached = ops.get(key)
        if (cached != null) return cached == "1"

        val exists = withContext(Dispatchers.IO) {
            followRepository.existsByFollowerIdAndFollowingIdAndStatus(
                followerId, followingId, FollowStatus.ACTIVE
            )
        }
        ops.set(key, if (exists) "1" else "0", IS_FOLLOWING_TTL)
        return exists
    }

    /**
     * 팔로우/언팔로우 이벤트 시 캐시 무효화
     * 팔로우 생성: follower_count(target), following_count(me), isFollowing(me->target) 무효화
     */
    fun invalidateOnFollow(followerId: String, followingId: String) {
        val keys = listOf(
            FollowCacheKeys.followerCount(followingId),   // 대상 팔로워 수
            FollowCacheKeys.followingCount(followerId),   // 내 팔로잉 수
            FollowCacheKeys.isFollowing(followerId, followingId),
            FollowCacheKeys.followingFirstPage(followerId), // 팔로잉 목록 1페이지
        )
        redisTemplate.delete(keys)
    }

    fun invalidateOnUnfollow(followerId: String, followingId: String) {
        // 무효화 대상 동일
        invalidateOnFollow(followerId, followingId)
    }

    /**
     * 팔로잉 목록 첫 페이지 캐싱 (가장 자주 조회되는 패턴)
     */
    suspend fun getFollowingFirstPage(
        userId: String,
        pageSize: Int,
    ): FollowPageResult {
        val key = FollowCacheKeys.followingFirstPage(userId)
        val cached = ops.get(key)
        if (cached != null) {
            return objectMapper.readValue(cached, FollowPageResult::class.java)
        }

        val result = withContext(Dispatchers.IO) {
            followQueryRepository.getFollowingPage(userId, cursor = null, pageSize)
        }
        ops.set(key, objectMapper.writeValueAsString(result), FIRST_PAGE_TTL)
        return result
    }
}
```

