# GraphQL Relay Connection Spec 준수

type FollowUser {
    userId: ID!
    nickname: String!
    profileImageUrl: String
    mannerScore: Float!
    followedAt: String!
}

type FollowEdge {
    node: FollowUser!
    cursor: String!         # Base64 인코딩된 커서
}

type PageInfo {
    hasNextPage: Boolean!
    hasPreviousPage: Boolean!
    startCursor: String
    endCursor: String
}

type FollowConnection {
    edges: [FollowEdge!]!
    pageInfo: PageInfo!
    totalCount: Int!        # 캐시된 값 사용
}

extend type Query {
    # 팔로잉 목록 (내가 팔로우하는 사람들)
    followings(
        first: Int = 20
        after: String       # endCursor 값
    ): FollowConnection!

    # 팔로워 목록 (나를 팔로우하는 사람들)
    followers(
        first: Int = 20
        after: String
    ): FollowConnection!

    # 특정 유저 팔로우 여부
    isFollowing(targetUserId: ID!): Boolean!
}

extend type Mutation {
    follow(targetUserId: ID!): Boolean!
    unfollow(targetUserId: ID!): Boolean!
}
